let storedFocusElement: Element | null = null;

const focusStore = {
  storeFocus() {
    storedFocusElement = document.activeElement;
  },

  clearStoredFocus() {
    storedFocusElement = null;
  },

  restoreFocus() {
    if (
      !storedFocusElement ||
      typeof (storedFocusElement as HTMLElement).focus !== 'function'
    ) {
      storedFocusElement = null;
      return;
    }
    try {
      (storedFocusElement as HTMLElement).focus({ preventScroll: true });
    } catch {
      // Element may have been detached from the DOM
    }
    storedFocusElement = null;
  },
};

export default focusStore;
